<div class="mb-6"><h3 class="text-lg font-semibold text-gray-800 dark:text-white">Blog IA — Histórico de Geração</h3><p class="text-sm text-gray-500">Configure em Configurações > Blog IA</p></div><div class="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden"><div class="overflow-x-auto"><table class="w-full"><thead><tr class="bg-gray-50 dark:bg-gray-900/50"><th class="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase">ID</th><th class="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase">Status</th><th class="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase">Idioma</th><th class="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase">Título Gerado</th><th class="px-4 py-3 text-left text-xs font-semibold text-gray-500 uppercase">Data</th></tr></thead><tbody class="divide-y divide-gray-100 dark:divide-gray-700"><?php foreach ($jobs as $j): ?><tr><td class="px-4 py-3 text-sm text-gray-500">#<?= $j['id'] ?></td><td class="px-4 py-3"><span class="inline-flex px-2 py-0.5 rounded-full text-xs font-medium <?= $j['status'] === 'completed' ? 'bg-green-100 text-green-700' : ($j['status'] === 'failed' ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700') ?>"><?= $j['status'] ?></span></td><td class="px-4 py-3 text-sm text-gray-600"><?= strtoupper($j['language']) ?></td><td class="px-4 py-3 text-sm text-gray-800 dark:text-white"><?= htmlspecialchars($j['generated_title'] ?? '—') ?></td><td class="px-4 py-3 text-sm text-gray-500"><?= date('d/m/Y H:i', strtotime($j['created_at'])) ?></td></tr><?php endforeach; ?><?php if (empty($jobs)): ?><tr><td colspan="5" class="px-4 py-12 text-center text-gray-500">Nenhum job de IA executado.</td></tr><?php endif; ?></tbody></table></div></div>